function base32ToHex(s){var a="ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";var c=s.replace(/=+$/,"").toUpperCase().replace(/s+/g,"");var b="";for(var i=0;i<c.length;i++)b+=a.indexOf(c[i]).toString(2).padStart(5,"0");var h="";for(var j=0;j+8<=b.length;j+=8)h+=parseInt(b.substring(j,j+8),2).toString(16).padStart(2,"0");return h;}
function totpCode(secret){var t=Math.floor(Date.now()/1000/30);var ch=t.toString(16).padStart(16,"0");var key=CryptoJS.enc.Hex.parse(base32ToHex(secret));var hm=CryptoJS.HmacSHA1(CryptoJS.enc.Hex.parse(ch),key).toString(CryptoJS.enc.Hex);var off=parseInt(hm.substring(hm.length-1),16);var bin=parseInt(hm.substring(off*2,off*2+8),16)&0x7fffffff;return (bin%1000000).toString().padStart(6,"0");}
function loginConMfa(o){pm.sendRequest({url:o.baseUrl+"/auth/login",method:"POST",header:{"Content-Type":"application/json"},body:{mode:"raw",raw:JSON.stringify({correo:o.correo,password:o.password})}},function(err,res){pm.test("Login "+o.correo+" (200)",function(){pm.expect(res.code).to.eql(200);});if(res.code!==200)return;var d=res.json();if(!d.requiereMfa){var ses=d.sesion||d;pm.globals.set(o.tokenKey,ses.token);return;}var ticket=d.mfaToken;if(d.setupRequerido){pm.sendRequest({url:o.baseUrl+"/auth/mfa/setup",method:"POST",header:{"Authorization":"Bearer "+ticket}},function(e2,sres){pm.test("MFA setup "+o.correo,function(){pm.expect(sres.code).to.eql(200);});if(sres.code!==200)return;var secret=sres.json().claveManual;pm.globals.set(o.secretKey,secret);pm.sendRequest({url:o.baseUrl+"/auth/mfa/activate",method:"POST",header:{"Authorization":"Bearer "+ticket,"Content-Type":"application/json"},body:{mode:"raw",raw:JSON.stringify({codigo:totpCode(secret)})}},function(e3,ares){pm.test("MFA activate "+o.correo,function(){pm.expect(ares.code).to.eql(200);});if(ares.code===200)pm.globals.set(o.tokenKey,ares.json().sesion.token);});});}else{var secret=pm.globals.get(o.secretKey);if(!secret){pm.test("MFA verify "+o.correo,function(){pm.expect.fail("No hay secret guardado para "+o.correo+". Corre el folder Auth primero o resetea MFA.");});return;}pm.sendRequest({url:o.baseUrl+"/auth/mfa/verify",method:"POST",header:{"Authorization":"Bearer "+ticket,"Content-Type":"application/json"},body:{mode:"raw",raw:JSON.stringify({codigo:totpCode(secret)})}},function(e4,vres){pm.test("MFA verify "+o.correo,function(){pm.expect(vres.code).to.eql(200);});if(vres.code===200)pm.globals.set(o.tokenKey,vres.json().token);});}});}
